<template>
    <div class="volume-slider">
      <div class="slider-track">
        <div class="slider-fill" :style="{ width: `${localVolume}%` }"></div>
      </div>
      <input
        type="range"
        min="0"
        max="100"
        v-model="localVolume"
        @input="updateVolume"
        class="slider-input"
      />
    </div>
  </template>
  
  <script>
  export default {
    name: 'VolumeSlider',
    props: {
      value: {
        type: Number,
        default: 50
      }
    },
    data() {
      return {
        localVolume: this.value
      };
    },
    methods: {
      updateVolume() {
        this.$emit('input', this.localVolume);
      }
    },
    watch: {
      value(newValue) {
        this.localVolume = newValue;
      }
    }
  }
  </script>
  
  <style scoped>
  .volume-slider {
    display: flex;
    align-items: center;
    position: relative;
    width: 100%;
  }
  
  .slider-track {
    width: 100%;
    height: 5px;
    background: #323233;
    border-radius: 5px;
    position: relative;
    margin: 0;
  }
  
  .slider-fill {
    height: 5px;
    background: #fdf74b; /* Цвет до ползунка */
    border-radius: 5px;
    position: absolute;
    top: 0;
    left: 0;
  }
  
  .slider-input {
    -webkit-appearance: none;
    width: 100%;
    height: 0px;
    background: #fdf74b;
    outline: none;
    position: absolute;
    top: -5px;
    left: 0;
  }
  
  .slider-input::-webkit-slider-runnable-track {
    width: 100%;
    height: 5px;
    background: transparent;
    border-radius: 5px;
  }
  
  .slider-input::-webkit-slider-thumb {
    -webkit-appearance: none;
    width: 20px;
    height: 20px;
    background: #fdf74b; /* Цвет ползунка */
    border-radius: 50%;
    cursor: pointer;
    position: relative;
    z-index: 1;
  }
  
  .slider-input::-moz-range-track {
    width: 100%;
    height: 5px;
    background: transparent;
    border-radius: 5px;
  }
  
  .slider-input::-moz-range-thumb {
    width: 20px;
    height: 20px;
    background: #fdf74b; /* Цвет ползунка */
    border-radius: 50%;
    cursor: pointer;
  }
  
  .slider-input::-ms-track {
    width: 100%;
    height: 5px;
    background: transparent;
    border-color: transparent;
    color: transparent;
  }
  
  .slider-input::-ms-fill-lower {
    background: #888; /* Цвет до ползунка */
  }
  
  .slider-input::-ms-fill-upper {
    background: #ddd; /* Цвет после ползунка */
  }
  
  .slider-input::-ms-thumb {
    width: 20px;
    height: 20px;
    background: #888; /* Цвет ползунка */
    border-radius: 50%;
    cursor: pointer;
    position: relative;
    z-index: 1;
  }
  </style>
  